import java.util.*;

// Generic Class
class Box<T> {
    private T item;
    public void put(T item) { this.item = item; }
    public T get() { return this.item; }
}

public class GenericsDemo {
    // Generic Method
    public static <E> void printArray(E[] array) {
        for (E element : array) System.out.print(element + " ");
        System.out.println();
    }

    // Wildcards & Bounding (PECS)
    public static double sumOfList(List<? extends Number> list) {
        double s = 0.0;
        for (Number n : list) s += n.doubleValue(); // Reading
        return s;
    }

    public static void main(String[] args) {
        Box<String> strBox = new Box<>();
        strBox.put("Generics");
        System.out.println(strBox.get());

        Integer[] ints = {1, 2, 3};
        printArray(ints);

        List<Integer> nums = List.of(1, 2, 3);
        System.out.println("Sum: " + sumOfList(nums));
    }
}

